## 2) One-step expected return backup

#For any \(V\), define:

#$ q(s,a) = \mathbb{E}[ R(s,a,s') + \gamma V(s') ]$

#We compute it using the model:
#- expected rental revenue (expected return)
#- moving cost
#- expected next value under the transition distribution

def q_from_v(mdp: CarRentalMDP, V: np.ndarray, s: Tuple[int,int], a: int, gamma: float) -> float:
    # 1) Obter probabilidades e receita (deve ter 4 espaços à esquerda)
    p1, p2, exp_revenue = mdp.expected_transition(s, a)
    
    # 2) Valor seguinte esperado
    exp_next = p1 @ (V @ p2)
    
    # 3) Custos e recompensa
    moving_cost = mdp.params.cost_per_moved * abs(a)
    reward = exp_revenue - moving_cost
    
    # 4) O return deve estar alinhado com o código acima (também com 4 espaços)
    return reward + gamma * exp_next

def bellman_expectation_backup_v(
    mdp: CarRentalMDP,
    V: np.ndarray,
    s: Tuple[int, int],
    policy: Dict[Tuple[int, int], int],
    gamma: float,
) -> float:
    a = policy[s]
    return q_from_v(mdp, V, s, a, gamma)


def bellman_optimality_backup_v(
    mdp: CarRentalMDP,
    V: np.ndarray,
    s: Tuple[int, int],
    gamma: float,
) -> float:
    best = -float("inf")
    for a in mdp.possible_actions(s):
        best = max(best, q_from_v(mdp, V, s, a, gamma))
    return best

## 3) Iterative Policy Evaluation

#Given a **deterministic** policy $(\pi(s)\in\mathcal{A}(s))$, update:

#$V(s) \leftarrow q(s, \pi(s))$

#until change is smaller than `theta`.

def zeros_V(mdp: CarRentalMDP) -> np.ndarray:
    return np.zeros((mdp.params.max_cars_1 + 1, mdp.params.max_cars_2 + 1), dtype=float)

def policy_evaluation(
    mdp: CarRentalMDP,
    policy: Dict[Tuple[int,int], int],
    gamma: float,
    theta: float = 1e-6,
    max_iters: int = 10_000,
) -> Tuple[np.ndarray, int]:
    V = zeros_V(mdp)

    for it in range(max_iters):
        delta = 0.0
        V_old = V.copy()

        for s in mdp.states():
            v_old = V[s[0], s[1]]
            V[s[0], s[1]] = bellman_expectation_backup_v(mdp, V_old, s, policy, gamma)
            delta = max(delta, abs(V[s[0], s[1]] - v_old))

        # Line 353 should be indented exactly 8 spaces (or 2 tabs)
        if delta < theta:
            return V, it + 1

    return V, max_iters

