def policy_iteration(mdp, gamma=0.9, theta=1e-6, max_outer=50):
    policy = {s: 0 for s in mdp.states()}
    history = []

    for outer in range(max_outer):
        V, iters = policy_evaluation(mdp, policy, gamma=gamma, theta=theta)
        new_policy, stable = policy_improvement(mdp, V, old_policy=policy, gamma=gamma)
        
        history.append((outer, iters, V.copy()))
        policy = new_policy

        if stable:
            return V, policy, history

    return V, policy, history
        #------------------

## 6) Value Iteration

#Bellman optimality update:

#$V(s) \leftarrow \max_{a \in \mathcal{A}(s)} q(s,a)$

#Then extract greedy policy from \(V\).

def value_iteration(
    mdp: CarRentalMDP,
    gamma: float = 0.9,
    theta: float = 1e-6,
    max_iters: int = 10_000,
):
    V = zeros_V(mdp)

    for it in range(max_iters):
        delta = 0.0
        V_old = V.copy()

        # TODO (E): Bellman optimality backup for each state.
        # v_new = ...
        #
        # --- SOLUTION ---
        # --- Your Code ---

        for s in mdp.states():
            v_new = bellman_optimality_backup_v(mdp, V_old, s, gamma)
            delta = max(delta, abs(v_new - V[s[0], s[1]]))
            V[s[0], s[1]] = v_new
 
        # Nível 2: Verificação de convergência (deve estar ALINHADO com o 'for s')
        if delta < theta:
            break  # Agora o break está dentro do loop 'for it'
 
    # Nível 3: Extrair política (fora do loop de iterações, dentro da função)
    pi = {}
    for s in mdp.states():
        best_a, best_q = None, -np.inf
        for a in mdp.possible_actions(s):
            q = q_from_v(mdp, V, s, a, gamma)
            if q > best_q:
                best_q, best_a = q, a
        pi[s] = best_a

    return V, pi, it + 1

## 7) Plotting utilities

#- Policy heatmap: action values (cars moved 1→2)
#- Value heatmap: state values

def policy_to_array(mdp: CarRentalMDP, policy: Dict[Tuple[int,int], int]) -> np.ndarray:
    arr = np.zeros((mdp.params.max_cars_1 + 1, mdp.params.max_cars_2 + 1), dtype=int)
    for (n1, n2), a in policy.items():
        arr[n1, n2] = a
    return arr

def plot_policy(mdp: CarRentalMDP, policy: Dict[Tuple[int,int], int], title: str = ""):
    arr = policy_to_array(mdp, policy)

    fig, ax = plt.subplots(figsize=(6,5))
    im = ax.imshow(arr, origin="lower")
    ax.set_title(title)
    ax.set_xlabel("# cars at location 2")
    ax.set_ylabel("# cars at location 1")

    # annotate
    for i in range(arr.shape[0]):
        for j in range(arr.shape[1]):
            ax.text(j, i, str(arr[i,j]), ha="center", va="center", fontsize=9)

    fig.colorbar(im, ax=ax, shrink=0.85)
    plt.show()

def plot_values(mdp: CarRentalMDP, V: np.ndarray, title: str = ""):
    fig, ax = plt.subplots(figsize=(6,5))
    im = ax.imshow(V, origin="lower")
    ax.set_title(title)
    ax.set_xlabel("# cars at location 2")
    ax.set_ylabel("# cars at location 1")
    fig.colorbar(im, ax=ax, shrink=0.85)
    plt.show()

